// server/lib/lock.ts
import { redis } from '../redis';
import crypto from 'crypto';
export async function withLock<T>(key: string, ttlSec: number, fn: () => Promise<T>): Promise<T | null> {
  const id = crypto.randomBytes(8).toString('hex');
  const acquired = await redis.set(`lock:${key}`, id, 'EX', ttlSec, 'NX');
  if (acquired !== 'OK') return null;
  try { return await fn(); }
  finally {
    await redis.eval(`if redis.call('get', KEYS[1]) == ARGV[1] then return redis.call('del', KEYS[1]) else return 0 end`, 1, `lock:${key}`, id);
  }
}

