type EventMap = { user_signed_up: { userId: string; email: string }; project_created: { projectId: string }; };
export class TypedEmitter<E extends Record<string, any>> {
  private listeners = new Map<keyof E, Set<(p: any) => void>>();
  on<K extends keyof E>(event: K, cb: (p: E[K]) => void) { (this.listeners.get(event) ?? this.listeners.set(event, new Set()).get(event)!).add(cb as any); return () => this.listeners.get(event)?.delete(cb as any); }
  emit<K extends keyof E>(event: K, payload: E[K]) { this.listeners.get(event)?.forEach(cb => cb(payload)); }
}

