// server/services/couponStackService.ts
export const couponStackService = {
  async canApply(existingCoupons: string[], newCode: string) {
    const existing = await CouponModel.find({ code: { $in: existingCoupons } });
    const novel = await CouponModel.findOne({ code: newCode });
    if (!novel) throw new NotFoundError();
    for (const e of existing) {
      const compatible = (e.stackableWith ?? []).includes(novel.code) || (novel.stackableWith ?? []).includes(e.code);
      if (!compatible) throw new ConflictError(`${newCode} cannot stack with ${e.code}`);
    }
    return true;
  }
};

